import { useState, useEffect } from 'react';
// Fix the import path - it should be relative to src/
import ApiService from '../Services/api';

const useChat = () => {
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [sessionId, setSessionId] = useState(null);

  useEffect(() => {
    initializeChat();
  }, []);

  const initializeChat = async () => {
    try {
      const session = await ApiService.createNewSession();
      setSessionId(session.session_id);
      
      // Add welcome message
      setMessages([{
        id: 1,
        type: 'bot',
        content: "Hello there! 👋 I'm StudyBuddy, your friendly AI companion! I'm here to help you with programming, mathematics, science, literature, and much more! What would you like to learn today? 📚✨",
        timestamp: new Date(),
        subject_area: 'general'
      }]);
    } catch (error) {
      console.error('Failed to initialize chat:', error);
    }
  };

  const sendMessage = async () => {
    if (!inputMessage.trim() || isLoading) return;

    const userMessage = {
      id: Date.now(),
      type: 'user',
      content: inputMessage,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputMessage('');
    setIsLoading(true);
    setIsTyping(true);

    try {
      const response = await ApiService.sendMessage(inputMessage, sessionId);
      
      // Simulate typing delay for better UX
      setTimeout(() => {
        const botMessage = {
          id: Date.now() + 1,
          type: 'bot',
          content: response.response || response.error,
          timestamp: new Date(),
          detected_language: response.detected_language,
          subject_area: response.subject_area
        };

        setMessages(prev => [...prev, botMessage]);
        setIsLoading(false);
        setIsTyping(false);
      }, 1000);

    } catch (error) {
      const errorMessage = {
        id: Date.now() + 1,
        type: 'bot',
        content: "Oops! Something went wrong. Please try again! 😅",
        timestamp: new Date()
      };
      
      setMessages(prev => [...prev, errorMessage]);
      setIsLoading(false);
      setIsTyping(false);
    }
  };

  const clearChat = async () => {
    try {
      if (sessionId) {
        await ApiService.clearSession(sessionId);
      }
      
      setMessages([{
        id: 1,
        type: 'bot',
        content: "Chat cleared! Ready for a fresh start! 🚀 What would you like to learn about?",
        timestamp: new Date(),
        subject_area: 'general'
      }]);
      
      // Create new session
      const session = await ApiService.createNewSession();
      setSessionId(session.session_id);
    } catch (error) {
      console.error('Failed to clear chat:', error);
    }
  };

  return {
    messages,
    inputMessage,
    setInputMessage,
    isLoading,
    isTyping,
    sessionId,
    sendMessage,
    clearChat
  };
};

export default useChat;
